INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ad6e6869-5d9c-4229-9644-9d7ac6a8d7e2', $q$Automatic REST API generation$q$, $q$Connects to a database or file store and instantly generates a fully documented REST API without manual coding.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ad6e6869-5d9c-4229-9644-9d7ac6a8d7e2', $q$Role-based access control$q$, $q$Granular, field-level permissions let administrators control exactly which users and applications can read or write specific data.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ad6e6869-5d9c-4229-9644-9d7ac6a8d7e2', $q$Broad connector library$q$, $q$Native connectors for MySQL, PostgreSQL, SQL Server, Oracle, MongoDB, Snowflake, SOAP services, and many other legacy and modern systems.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ad6e6869-5d9c-4229-9644-9d7ac6a8d7e2', $q$Server-side scripting$q$, $q$Custom business logic can be added using Node.js, PHP, or Python scripting hooks layered on top of generated APIs.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ad6e6869-5d9c-4229-9644-9d7ac6a8d7e2', $q$Self-hosted deployment$q$, $q$Runs via Docker or Kubernetes on-premises or in a private cloud, supporting air-gapped and highly regulated environments.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ad6e6869-5d9c-4229-9644-9d7ac6a8d7e2', $q$OpenAPI documentation$q$, $q$Every generated API ships with live, interactive Swagger/OpenAPI documentation for developers and integrators.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ad6e6869-5d9c-4229-9644-9d7ac6a8d7e2', $q$API key and rate limit management$q$, $q$Issue and revoke API keys and enforce rate limits to protect backend systems from abuse or overload.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ad6e6869-5d9c-4229-9644-9d7ac6a8d7e2', $q$Governance and logging$q$, $q$Detailed audit logs track every API call, supporting compliance requirements in healthcare, finance, and government.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ad6e6869-5d9c-4229-9644-9d7ac6a8d7e2', $q$Dramatically reduces the time needed to expose legacy databases and systems as modern APIs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ad6e6869-5d9c-4229-9644-9d7ac6a8d7e2', $q$Strong fit for regulated industries thanks to self-hosted and air-gapped deployment options$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ad6e6869-5d9c-4229-9644-9d7ac6a8d7e2', $q$Broad connector support spanning modern databases and older SOAP-based legacy systems$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ad6e6869-5d9c-4229-9644-9d7ac6a8d7e2', $q$Free open-source tier available for learning and small personal projects$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ad6e6869-5d9c-4229-9644-9d7ac6a8d7e2', $q$Paid tiers are priced for enterprise IT budgets, with limited options for small teams or startups$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ad6e6869-5d9c-4229-9644-9d7ac6a8d7e2', $q$Requires infrastructure knowledge (Docker/Kubernetes) to deploy and maintain compared to pure SaaS API gateways$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ad6e6869-5d9c-4229-9644-9d7ac6a8d7e2', $q$The free Open Source tier is restricted to a single database connector$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ad6e6869-5d9c-4229-9644-9d7ac6a8d7e2', $q$Enterprise and Federal pricing is custom and not transparently published$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ad6e6869-5d9c-4229-9644-9d7ac6a8d7e2', $q$What does DreamFactory do?$q$, $q$DreamFactory automatically generates secure, documented REST APIs from databases, file stores, and legacy systems, removing the need to hand-code API endpoints.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ad6e6869-5d9c-4229-9644-9d7ac6a8d7e2', $q$Is DreamFactory free?$q$, $q$There is a free, open-source tier limited to a single PostgreSQL connector. Paid self-hosted tiers start at roughly $1,500 per month billed annually for broader connector access and enterprise features.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ad6e6869-5d9c-4229-9644-9d7ac6a8d7e2', $q$Can DreamFactory be self-hosted?$q$, $q$Yes, DreamFactory is primarily deployed self-hosted via Docker or Kubernetes on a customer's own servers or private cloud, which is a major reason regulated industries choose it.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ad6e6869-5d9c-4229-9644-9d7ac6a8d7e2', $q$Who owns DreamFactory?$q$, $q$DreamFactory Software has been owned by Xenon Partners, a technology-focused private equity firm, since acquiring the company in 2018.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ad6e6869-5d9c-4229-9644-9d7ac6a8d7e2', $q$What are the main alternatives to DreamFactory?$q$, $q$Common alternatives include Kong, Google Cloud Apigee, WSO2 API Manager, Tyk, and API design tools like Postman, though most of these require manual API design rather than automatic generation from a data source.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ad6e6869-5d9c-4229-9644-9d7ac6a8d7e2', $q$Does DreamFactory support AI use cases?$q$, $q$Yes, DreamFactory positions itself as a governed data layer that lets AI agents and large language models query enterprise databases through generated, access-controlled APIs rather than direct database access.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ad6e6869-5d9c-4229-9644-9d7ac6a8d7e2', $q$Legacy system modernization$q$, $q$IT teams expose decades-old databases or SOAP-based legacy systems as modern REST APIs without rewriting the underlying systems.$q$, $q$Enterprise IT and platform engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ad6e6869-5d9c-4229-9644-9d7ac6a8d7e2', $q$Regulated-industry API access$q$, $q$Government, healthcare, and financial organizations deploy DreamFactory on-premises to meet strict compliance and data-residency requirements.$q$, $q$Government agencies and regulated enterprises$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ad6e6869-5d9c-4229-9644-9d7ac6a8d7e2', $q$Governed AI data access$q$, $q$Organizations use DreamFactory to give AI agents controlled, auditable API access to internal databases instead of direct, unrestricted database connections.$q$, $q$AI and data engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ad6e6869-5d9c-4229-9644-9d7ac6a8d7e2', $q$Open Source$q$, $q$Free$q$, $q$Free$q$, NULL, $q$["Single PostgreSQL connector","Basic API generation","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ad6e6869-5d9c-4229-9644-9d7ac6a8d7e2', $q$Essential$q$, $q$$1,500/month$q$, $q$Billed annually$q$, NULL, $q$["One database connector of choice","Unlimited roles, keys, and API requests"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ad6e6869-5d9c-4229-9644-9d7ac6a8d7e2', $q$Professional$q$, $q$$4,000/month$q$, $q$Billed annually$q$, NULL, $q$["Nearly all database connectors","Role-based access control","API scripting"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ad6e6869-5d9c-4229-9644-9d7ac6a8d7e2', $q$Enterprise$q$, $q$Custom (per vCPU)$q$, $q$Billed annually$q$, NULL, $q$["All connectors included","Authentication and rate limiting","Logging and governance"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ad6e6869-5d9c-4229-9644-9d7ac6a8d7e2', $q$Federal Docker$q$, $q$Custom$q$, $q$Billed annually$q$, NULL, $q$["NIST-aligned compliance controls","Full SBOM and CVE scans","All enterprise-level capabilities"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ad6e6869-5d9c-4229-9644-9d7ac6a8d7e2', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$DreamFactory is an API management platform that automatically generates secure, fully documented REST APIs from existing databases, file stores, and legacy enterprise systems. Instead of developers hand-coding endpoints, DreamFactory introspects a data source's schema and instantly produces a live API with CRUD operations, authentication, and OpenAPI documentation.$q$, $q$The platform is designed to be deployed self-hosted, typically via Docker or Kubernetes on a customer's own infrastructure, which makes it a common choice for government agencies, healthcare organizations, and financial institutions with strict data-residency and compliance requirements.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ad6e6869-5d9c-4229-9644-9d7ac6a8d7e2', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core capabilities include automatic REST API generation from SQL and NoSQL databases, role-based access control with granular permissions per table and field, API key management, and rate limiting to protect backend systems from overload.$q$, $q$DreamFactory also supports server-side scripting in Node.js, PHP, and Python for custom business logic, native connectors for dozens of databases and legacy protocols such as SOAP, and logging and governance tooling that gives IT teams an audit trail of every API call, which is essential when exposing data to AI agents or third-party applications.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ad6e6869-5d9c-4229-9644-9d7ac6a8d7e2', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$DreamFactory offers a free Open Source tier limited to a single PostgreSQL connector, followed by paid self-hosted tiers: Essential (around $1,500/month, one database connector), Professional (around $4,000/month, nearly all connectors plus RBAC and scripting), and Enterprise (custom, per-vCPU pricing with every connector and full governance features).$q$, $q$A Federal Docker edition adds NIST-aligned compliance controls for government buyers, and optional Basic, Pro, and Enterprise support add-ons provide dedicated engineering assistance for an additional monthly fee. All paid tiers are billed annually and priced around infrastructure footprint rather than simple per-seat counts.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ad6e6869-5d9c-4229-9644-9d7ac6a8d7e2', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ad6e6869-5d9c-4229-9644-9d7ac6a8d7e2', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ad6e6869-5d9c-4229-9644-9d7ac6a8d7e2', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ad6e6869-5d9c-4229-9644-9d7ac6a8d7e2', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ad6e6869-5d9c-4229-9644-9d7ac6a8d7e2', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$Visual workflow automation$q$, $q$Build multi-step, conditional customer journeys triggered by browsing, cart, and purchase behavior.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$Native ecommerce integrations$q$, $q$Direct connections to Shopify, WooCommerce, and BigCommerce pull in order and product data automatically.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$Email and SMS in one platform$q$, $q$Combine email campaigns with SMS messaging inside the same automated workflows and segments.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$Dynamic segmentation$q$, $q$Customer segments update automatically in real time as behavior and purchase history change.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$On-site campaigns$q$, $q$Pop-ups and embedded forms help convert site visitors into subscribers without third-party tools.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$Open API access$q$, $q$Developers can build custom integrations and extend Drip's automation beyond native connectors.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$Unlimited sub-accounts$q$, $q$Agencies and multi-brand businesses can manage several stores under one Drip account.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$All-inclusive feature set$q$, $q$Every paid plan includes the full feature set regardless of price tier, with pricing based only on contact count.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$Simple, transparent pricing based only on contact count with no feature gating$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$Deep native integrations with major ecommerce platforms like Shopify and WooCommerce$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$Combines email and SMS automation in a single workflow builder$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$14-day free trial lets new users test the full feature set before paying$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$Focused specifically on ecommerce, making it a poor fit for non-retail businesses$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$Live chat support is limited to accounts on $99/month plans or higher$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$Pricing rises quickly as contact lists grow, which can be costly for large lists$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$Fewer advanced analytics and reporting options compared to some larger competitors like Klaviyo$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$What is Drip used for?$q$, $q$Drip is a marketing automation platform for ecommerce brands, used to build automated email and SMS journeys such as welcome series, cart-recovery sequences, and post-purchase campaigns.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$How much does Drip cost?$q$, $q$Drip pricing starts at $39/month for up to 2,500 contacts and scales with contact count, reaching $1,199/month for 100,000 contacts. Every plan includes the full feature set.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$Does Drip offer a free trial?$q$, $q$Yes, Drip offers a 14-day free trial that gives access to the full platform before requiring payment.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$Which ecommerce platforms does Drip integrate with?$q$, $q$Drip has native integrations with Shopify, WooCommerce, and BigCommerce, along with an open API for custom integrations.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$Who owns Drip?$q$, $q$Drip was founded in 2012 by Rob Walling and Derrick Reimer, acquired by Leadpages in 2016, and became an independently operated company again after Leadpages was acquired by Redbrick Technologies in 2020.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$What are the main alternatives to Drip?$q$, $q$The most common alternatives are Klaviyo, Omnisend, and Sendlane, all of which also focus on ecommerce email and SMS marketing automation.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$Cart abandonment recovery$q$, $q$Automatically trigger email and SMS sequences when a shopper adds items to their cart but does not complete checkout.$q$, $q$Ecommerce store owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$Post-purchase customer retention$q$, $q$Build automated win-back and loyalty campaigns to turn one-time buyers into repeat customers.$q$, $q$DTC and ecommerce marketing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$Multi-brand agency management$q$, $q$Agencies use unlimited sub-accounts to manage marketing automation for several ecommerce clients from one Drip account.$q$, $q$Ecommerce marketing agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$2,500 Contacts$q$, $q$$39/month$q$, $q$Monthly (annual discount available)$q$, NULL, $q$["Unlimited email sends","Up to 50 workflows","Dynamic segmentation","Open API access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$5,000 Contacts$q$, $q$$89/month$q$, $q$Monthly (annual discount available)$q$, NULL, $q$["Full feature set included","On-site pop-ups and forms","Unlimited sub-accounts"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$10,000 Contacts$q$, $q$$154/month$q$, $q$Monthly (annual discount available)$q$, NULL, $q$["Full feature set included","SMS and email automation"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$30,000 Contacts$q$, $q$$449/month$q$, $q$Monthly (annual discount available)$q$, NULL, $q$["Full feature set included","Live chat support"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$100,000 Contacts$q$, $q$$1,199/month$q$, $q$Monthly (annual discount available)$q$, NULL, $q$["Full feature set included","Live chat support","Priority account handling"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Drip is a marketing automation platform purpose-built for ecommerce brands, combining email, SMS, and on-site campaigns with behavioral segmentation drawn from actual store and purchase data.$q$, $q$Rather than serving as a general-purpose email tool, Drip integrates directly with platforms like Shopify, WooCommerce, and BigCommerce so that automated workflows can trigger off real customer actions such as browsing a product, abandoning a cart, or completing a purchase.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Drip's visual workflow builder supports multi-step automated customer journeys with conditional branching across email and SMS, alongside dynamic segments that update automatically as customer behavior changes.$q$, $q$The platform also includes on-site pop-ups and forms for list growth, native ecommerce integrations that pull in order and product-catalog data, an open API for custom development, and unlimited sub-accounts for agencies managing multiple stores.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Drip uses a single-tier pricing model based entirely on contact count, with every feature included at every price point. Plans start at $39 per month for up to 2,500 contacts and scale up through $89/month (5,000 contacts), $154/month (10,000 contacts), $449/month (30,000 contacts), and $1,199/month (100,000 contacts).$q$, $q$All paid plans include unlimited email sends, up to 50 workflows, full segmentation, and API access; live chat support unlocks at $99/month and above. A 14-day free trial is available, and annual billing offers roughly a 25 percent discount versus monthly billing.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('381765dd-2a06-4f6d-87c2-9252da262faf', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b721f7a1-30be-4fe9-aaef-0d63697db57b', $q$Container-native pipeline steps$q$, $q$Every build step runs inside its own Docker container, giving isolated and reproducible execution environments.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b721f7a1-30be-4fe9-aaef-0d63697db57b', $q$Declarative YAML pipelines$q$, $q$Pipelines are defined in a version-controlled .drone.yml file, following an infrastructure-as-code approach.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b721f7a1-30be-4fe9-aaef-0d63697db57b', $q$Extensive plugin ecosystem$q$, $q$Hundreds of community-built Drone plugins, themselves Docker containers, handle deployment, notifications, and registry pushes.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b721f7a1-30be-4fe9-aaef-0d63697db57b', $q$Language-agnostic builds$q$, $q$Since any Docker image can be used, Drone can build and test projects in virtually any programming language or framework.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b721f7a1-30be-4fe9-aaef-0d63697db57b', $q$Self-hosted deployment$q$, $q$Runs entirely on a team's own servers or Kubernetes cluster, giving full control over infrastructure and data.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b721f7a1-30be-4fe9-aaef-0d63697db57b', $q$Horizontally scalable runners$q$, $q$Build execution can be scaled out across multiple runner nodes to handle larger or parallel build workloads.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b721f7a1-30be-4fe9-aaef-0d63697db57b', $q$Git-triggered automation$q$, $q$Pipelines automatically trigger on git events such as pushes and pull requests from popular source control providers.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b721f7a1-30be-4fe9-aaef-0d63697db57b', $q$Open-source community edition$q$, $q$The core platform is free and open source, maintained as Harness CI Community Edition after Harness's acquisition of Drone.io.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b721f7a1-30be-4fe9-aaef-0d63697db57b', $q$Genuinely free and open-source core product with no forced feature paywall$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b721f7a1-30be-4fe9-aaef-0d63697db57b', $q$Container-native design gives strong isolation and reproducibility for every pipeline step$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b721f7a1-30be-4fe9-aaef-0d63697db57b', $q$Large, mature plugin ecosystem built up over more than a decade of community use$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b721f7a1-30be-4fe9-aaef-0d63697db57b', $q$Backed by Harness, giving the project ongoing maintenance and enterprise upgrade path$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b721f7a1-30be-4fe9-aaef-0d63697db57b', $q$Requires self-hosting and Docker/Kubernetes knowledge, unlike fully managed CI services$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b721f7a1-30be-4fe9-aaef-0d63697db57b', $q$Enterprise features and support require moving to Harness's separate commercial product$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b721f7a1-30be-4fe9-aaef-0d63697db57b', $q$Smaller active community and slower feature velocity compared to GitHub Actions or GitLab CI$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b721f7a1-30be-4fe9-aaef-0d63697db57b', $q$Documentation for the community edition is less extensive than for Harness's commercial CI offering$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b721f7a1-30be-4fe9-aaef-0d63697db57b', $q$Is Drone CI free?$q$, $q$Yes, Drone CI's Community Edition is fully open source and free to self-host. Harness also offers a separate paid enterprise CI/CD product built on the same foundation.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b721f7a1-30be-4fe9-aaef-0d63697db57b', $q$Who maintains Drone CI today?$q$, $q$Drone CI is maintained by Harness, which acquired Drone.io in 2020 and rebranded the open-source project as Harness CI Community Edition while committing to keep it free and open source.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b721f7a1-30be-4fe9-aaef-0d63697db57b', $q$How does Drone CI execute pipeline steps?$q$, $q$Every pipeline step runs inside its own Docker container, defined declaratively in a .drone.yml file checked into the project's source repository.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b721f7a1-30be-4fe9-aaef-0d63697db57b', $q$What are Drone plugins?$q$, $q$Drone plugins are reusable Docker containers that perform common pipeline tasks such as deploying to a cloud provider, pushing to a container registry, or sending a Slack notification.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b721f7a1-30be-4fe9-aaef-0d63697db57b', $q$What are the main alternatives to Drone CI?$q$, $q$Common alternatives include Jenkins, GitLab CI/CD, GitHub Actions, CircleCI, and Concourse.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b721f7a1-30be-4fe9-aaef-0d63697db57b', $q$Who originally created Drone CI?$q$, $q$Drone CI was created in 2012 by developer Brad Rydzewski as an independent open-source, container-native CI project before Harness acquired it in 2020.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b721f7a1-30be-4fe9-aaef-0d63697db57b', $q$Self-hosted container-native CI/CD$q$, $q$Teams standardized on Docker or Kubernetes run Drone to build, test, and deploy applications entirely within container-based pipelines.$q$, $q$DevOps and platform engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b721f7a1-30be-4fe9-aaef-0d63697db57b', $q$Multi-language build pipelines$q$, $q$Organizations with polyglot codebases use Drone's any-Docker-image approach to run builds for different languages without maintaining separate CI servers.$q$, $q$Software engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b721f7a1-30be-4fe9-aaef-0d63697db57b', $q$On-premises compliance-driven CI$q$, $q$Teams that cannot use cloud-hosted CI due to data residency or compliance rules self-host Drone entirely within their own infrastructure.$q$, $q$Regulated enterprises and security-conscious engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b721f7a1-30be-4fe9-aaef-0d63697db57b', $q$Community Edition$q$, $q$Free$q$, $q$Free (self-hosted)$q$, NULL, $q$["Container-native pipelines","Unlimited self-hosted usage","Community plugin ecosystem","Open-source license"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b721f7a1-30be-4fe9-aaef-0d63697db57b', $q$Harness CI Enterprise$q$, $q$Custom pricing$q$, $q$Custom / annual contract$q$, NULL, $q$["Managed hosting option","Dedicated support","Advanced security and compliance controls"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b721f7a1-30be-4fe9-aaef-0d63697db57b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Drone CI is an open-source, container-native continuous integration and delivery platform where every pipeline step runs as an isolated Docker container, configured through a declarative YAML file checked into the source repository.$q$, $q$Originally created as an independent open-source project, Drone is now maintained as Harness CI Community Edition following Harness's 2020 acquisition of Drone.io, with Harness offering a separate commercial enterprise CI/CD product built on the same foundation.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b721f7a1-30be-4fe9-aaef-0d63697db57b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Every pipeline step executes inside its own Docker container, giving teams full control over the runtime environment for builds, tests, and deployments without dependency conflicts between steps.$q$, $q$Pipelines are defined in a `.drone.yml` file for git-versioned, infrastructure-as-code configuration, and Drone's plugin ecosystem lets teams reuse hundreds of community-built container plugins for common tasks like deploying to cloud providers, pushing container images, or sending notifications.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b721f7a1-30be-4fe9-aaef-0d63697db57b', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Drone CI's core Community Edition is fully open source and free to self-host on a team's own infrastructure, with no licensing cost.$q$, $q$Organizations needing managed hosting, dedicated support, or advanced enterprise security and compliance features can upgrade to Harness's commercial CI/CD platform, which is sold at custom, quote-based pricing rather than published self-serve rates.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b721f7a1-30be-4fe9-aaef-0d63697db57b', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b721f7a1-30be-4fe9-aaef-0d63697db57b', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b721f7a1-30be-4fe9-aaef-0d63697db57b', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b721f7a1-30be-4fe9-aaef-0d63697db57b', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b721f7a1-30be-4fe9-aaef-0d63697db57b', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ddb9f7aa-c8c0-4280-bea1-ba03e21c1bf6', $q$Self-hosted game library$q$, $q$Run the entire platform on your own hardware, keeping full ownership of your game data and library.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ddb9f7aa-c8c0-4280-bea1-ba03e21c1bf6', $q$Automatic metadata imports$q$, $q$Pulls cover art and game details automatically from IGDB, GiantBomb, and PCGamingWiki.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ddb9f7aa-c8c0-4280-bea1-ba03e21c1bf6', $q$Built-in storefront view$q$, $q$Browse, filter, and curate a personal game collection through a commercial-store-like interface.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ddb9f7aa-c8c0-4280-bea1-ba03e21c1bf6', $q$Cross-platform desktop client$q$, $q$A native client handles downloading, installing, and launching games across platforms.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ddb9f7aa-c8c0-4280-bea1-ba03e21c1bf6', $q$Flexible authentication$q$, $q$Supports both simple username/password accounts and SSO integration for teams and organizations.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ddb9f7aa-c8c0-4280-bea1-ba03e21c1bf6', $q$Rich metadata editing$q$, $q$Full Markdown and image support for customizing individual game listings.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ddb9f7aa-c8c0-4280-bea1-ba03e21c1bf6', $q$News and update system$q$, $q$Administrators can publish news and updates visible both in-browser and inside the desktop client.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ddb9f7aa-c8c0-4280-bea1-ba03e21c1bf6', $q$Docker-based deployment$q$, $q$Installs via Docker or Docker Compose, with a documented quickstart for setup in around ten minutes.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ddb9f7aa-c8c0-4280-bea1-ba03e21c1bf6', $q$Completely free and open source with no subscription or licensing cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ddb9f7aa-c8c0-4280-bea1-ba03e21c1bf6', $q$Full data ownership since everything runs on the user's own hardware$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ddb9f7aa-c8c0-4280-bea1-ba03e21c1bf6', $q$Automatic metadata enrichment removes most manual cataloging work$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ddb9f7aa-c8c0-4280-bea1-ba03e21c1bf6', $q$Familiar, commercial-storefront-style interface makes it approachable for non-technical users$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ddb9f7aa-c8c0-4280-bea1-ba03e21c1bf6', $q$Requires self-hosting knowledge and infrastructure, unlike a plug-and-play commercial storefront$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ddb9f7aa-c8c0-4280-bea1-ba03e21c1bf6', $q$Only supports DRM-free games, so it cannot be used with DRM-protected titles from commercial stores$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ddb9f7aa-c8c0-4280-bea1-ba03e21c1bf6', $q$As a volunteer-maintained project, support relies on community channels rather than dedicated staff$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ddb9f7aa-c8c0-4280-bea1-ba03e21c1bf6', $q$Smaller game database integrations compared to the catalog depth of major commercial platforms$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ddb9f7aa-c8c0-4280-bea1-ba03e21c1bf6', $q$What is Drop OSS?$q$, $q$Drop OSS is a free, open-source, self-hosted game distribution platform that gives users a Steam-like store and library experience for their own DRM-free games.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ddb9f7aa-c8c0-4280-bea1-ba03e21c1bf6', $q$Is Drop free to use?$q$, $q$Yes, Drop is entirely free and open source under the AGPLv3 license. The only cost is the hardware or hosting used to run it.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ddb9f7aa-c8c0-4280-bea1-ba03e21c1bf6', $q$How do I install Drop?$q$, $q$Drop is typically installed via Docker or Docker Compose, with the project documenting a quickstart setup that takes roughly ten minutes.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ddb9f7aa-c8c0-4280-bea1-ba03e21c1bf6', $q$Can Drop be used with DRM-protected games?$q$, $q$No, Drop is designed for DRM-free game distribution and is not built to bypass copy protection on commercially DRM-locked titles.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ddb9f7aa-c8c0-4280-bea1-ba03e21c1bf6', $q$Who maintains Drop OSS?$q$, $q$Drop is maintained by the Drop OSS open-source community, with development coordinated on GitHub and support through Discord and GitHub Discussions.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ddb9f7aa-c8c0-4280-bea1-ba03e21c1bf6', $q$What license does Drop use?$q$, $q$Drop is released under the AGPLv3 license, a strong copyleft open-source license.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ddb9f7aa-c8c0-4280-bea1-ba03e21c1bf6', $q$Personal DRM-free game library$q$, $q$Individuals self-host Drop to organize and access their DRM-free game purchases from a single, private storefront-style interface.$q$, $q$Self-hosting enthusiasts and gamers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ddb9f7aa-c8c0-4280-bea1-ba03e21c1bf6', $q$Small community game sharing$q$, $q$Gaming communities or households run a shared Drop instance so members can browse and play from a common DRM-free game library.$q$, $q$Home-lab operators and gaming communities$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ddb9f7aa-c8c0-4280-bea1-ba03e21c1bf6', $q$Indie and homebrew game distribution$q$, $q$Indie developers or hobbyist communities use Drop to distribute their own games with a polished, store-like browsing experience.$q$, $q$Indie game developers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ddb9f7aa-c8c0-4280-bea1-ba03e21c1bf6', $q$Self-Hosted$q$, $q$Free$q$, $q$Free (open source)$q$, NULL, $q$["Full platform access","AGPLv3 open-source license","Self-hosted on your own hardware","Community support via Discord and GitHub"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ddb9f7aa-c8c0-4280-bea1-ba03e21c1bf6', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Drop (Drop OSS) is a free, open-source, self-hosted game distribution platform that gives users a Steam-like store and library experience for their own collection of DRM-free games, running entirely on hardware the user controls.$q$, $q$The project is maintained by the Drop OSS open-source community, released under the AGPLv3 license, with development coordinated publicly on GitHub and support available via Discord and GitHub Discussions.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ddb9f7aa-c8c0-4280-bea1-ba03e21c1bf6', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Drop automatically imports cover art and game details from IGDB, GiantBomb, and PCGamingWiki, and includes a built-in store view for browsing, filtering, and organizing a game collection, alongside a cross-platform desktop client for downloading and launching games.$q$, $q$The platform supports both simple account authentication and SSO for organizations, full Markdown and image editing for custom game listings, and a news system for publishing updates visible in-browser and in the desktop client.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ddb9f7aa-c8c0-4280-bea1-ba03e21c1bf6', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Drop is entirely free and open source under the AGPLv3 license, with no paid tiers, subscriptions, or commercial editions. The only cost is the server or cloud hardware a user chooses to self-host it on.$q$, $q$Deployment is typically handled via Docker or Docker Compose, with the project's documentation describing a quickstart setup that takes roughly ten minutes for a basic instance.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ddb9f7aa-c8c0-4280-bea1-ba03e21c1bf6', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ddb9f7aa-c8c0-4280-bea1-ba03e21c1bf6', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ddb9f7aa-c8c0-4280-bea1-ba03e21c1bf6', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ddb9f7aa-c8c0-4280-bea1-ba03e21c1bf6', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ddb9f7aa-c8c0-4280-bea1-ba03e21c1bf6', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ddb9f7aa-c8c0-4280-bea1-ba03e21c1bf6', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('09bfad13-d346-4bb4-8adf-3ff6863d687e', $q$Automatic file sync$q$, $q$Files placed in the Dropbox folder sync automatically across all connected devices using efficient block-level sync.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('09bfad13-d346-4bb4-8adf-3ff6863d687e', $q$File version history$q$, $q$Restore earlier file versions or recover deleted files, with retention windows ranging from 30 days to a full year depending on plan.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('09bfad13-d346-4bb4-8adf-3ff6863d687e', $q$Shared team folders$q$, $q$Teams can collaborate in shared folders with granular permission controls for viewing and editing.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('09bfad13-d346-4bb4-8adf-3ff6863d687e', $q$Cross-platform apps$q$, $q$Native apps for Windows, Mac, iOS, and Android keep files accessible and synced everywhere.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('09bfad13-d346-4bb4-8adf-3ff6863d687e', $q$Dropbox Paper$q$, $q$A lightweight collaborative document tool built into the Dropbox ecosystem for notes and team docs.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('09bfad13-d346-4bb4-8adf-3ff6863d687e', $q$Dropbox Sign integration$q$, $q$Send and manage e-signature requests directly from Dropbox using the company's Dropbox Sign product.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('09bfad13-d346-4bb4-8adf-3ff6863d687e', $q$Dropbox Dash AI search$q$, $q$An AI-powered universal search tool that finds content across Dropbox and other connected cloud applications.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('09bfad13-d346-4bb4-8adf-3ff6863d687e', $q$Large file transfer$q$, $q$Send files up to 100GB (on higher-tier plans) to anyone, even people without a Dropbox account.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('09bfad13-d346-4bb4-8adf-3ff6863d687e', $q$Mature, reliable sync technology with a long track record across platforms$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('09bfad13-d346-4bb4-8adf-3ff6863d687e', $q$Broad ecosystem of adjacent tools (Sign, Paper, Dash) integrated into one account$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('09bfad13-d346-4bb4-8adf-3ff6863d687e', $q$Generous file version history and recovery options on paid plans$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('09bfad13-d346-4bb4-8adf-3ff6863d687e', $q$Strong cross-platform support across desktop, web, iOS, and Android$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('09bfad13-d346-4bb4-8adf-3ff6863d687e', $q$Free plan storage (2GB) is significantly smaller than several competitors' free tiers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('09bfad13-d346-4bb4-8adf-3ff6863d687e', $q$Business plans often require a 3-user minimum, adding cost for very small teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('09bfad13-d346-4bb4-8adf-3ff6863d687e', $q$Pricing has increased over time relative to some storage-focused competitors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('09bfad13-d346-4bb4-8adf-3ff6863d687e', $q$Advanced security and compliance features are reserved for the highest, custom-priced tiers$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('09bfad13-d346-4bb4-8adf-3ff6863d687e', $q$How much does Dropbox cost?$q$, $q$Dropbox offers a free Basic plan with 2GB of storage. Paid personal plans start around $11.99/month for 2TB (Plus), and business plans start around $18-20 per user per month with a typical 3-user minimum.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('09bfad13-d346-4bb4-8adf-3ff6863d687e', $q$Who founded Dropbox?$q$, $q$Dropbox was founded in 2007 by MIT students Drew Houston and Arash Ferdowsi in San Francisco.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('09bfad13-d346-4bb4-8adf-3ff6863d687e', $q$What is the difference between Dropbox Plus and Professional?$q$, $q$Plus includes 2TB of storage and 30-day version history for individuals, while Professional includes 3TB of storage, 180-day version history, and larger file transfer limits.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('09bfad13-d346-4bb4-8adf-3ff6863d687e', $q$Is Dropbox Sign part of Dropbox?$q$, $q$Yes, Dropbox Sign (formerly HelloSign) is Dropbox's e-signature product, acquired in 2019 and rebranded under the Dropbox name in 2022.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('09bfad13-d346-4bb4-8adf-3ff6863d687e', $q$What are the main alternatives to Dropbox?$q$, $q$The most common alternatives are Google Drive, Microsoft OneDrive, Box, and pCloud.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('09bfad13-d346-4bb4-8adf-3ff6863d687e', $q$Does Dropbox offer a business plan?$q$, $q$Yes, Dropbox offers Standard, Advanced, and custom-priced Enterprise business plans with pooled team storage, admin controls, and advanced security features.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('09bfad13-d346-4bb4-8adf-3ff6863d687e', $q$Personal cloud backup and sync$q$, $q$Individuals use Dropbox to automatically back up and sync personal files across their computers and phones.$q$, $q$Individual professionals and freelancers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('09bfad13-d346-4bb4-8adf-3ff6863d687e', $q$Team file collaboration$q$, $q$Small and mid-sized businesses use shared team folders and permission controls to collaborate on documents.$q$, $q$Small and mid-sized business teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('09bfad13-d346-4bb4-8adf-3ff6863d687e', $q$Enterprise-grade file governance$q$, $q$Large organizations use Dropbox's Advanced and Enterprise plans for centralized admin controls, compliance, and security across thousands of users.$q$, $q$Enterprise IT and compliance teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('09bfad13-d346-4bb4-8adf-3ff6863d687e', $q$Basic$q$, $q$Free$q$, $q$Free$q$, NULL, $q$["2GB storage","File sync across devices","Basic sharing"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('09bfad13-d346-4bb4-8adf-3ff6863d687e', $q$Plus$q$, $q$$11.99/month$q$, $q$Monthly (or ~$9.99/month billed annually)$q$, NULL, $q$["2TB storage","30-day file recovery","File transfers up to 50GB"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('09bfad13-d346-4bb4-8adf-3ff6863d687e', $q$Professional$q$, $q$$19.99/month$q$, $q$Monthly (or ~$16.58/month billed annually)$q$, NULL, $q$["3TB storage","180-day version history","File transfers up to 100GB"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('09bfad13-d346-4bb4-8adf-3ff6863d687e', $q$Standard (Business)$q$, $q$~$18-20/user/month$q$, $q$Per user/month, 3-user minimum$q$, NULL, $q$["Pooled team storage from 9TB","Team folders","Admin controls"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('09bfad13-d346-4bb4-8adf-3ff6863d687e', $q$Advanced (Business)$q$, $q$Custom (per user)$q$, $q$Per user/month$q$, NULL, $q$["Larger pooled storage","1-year file restoration","Single sign-on"]$q$::jsonb, 4);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('09bfad13-d346-4bb4-8adf-3ff6863d687e', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Custom / annual contract$q$, NULL, $q$["Advanced security and compliance","Dedicated support","Custom deployment options"]$q$::jsonb, 5);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('09bfad13-d346-4bb4-8adf-3ff6863d687e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Dropbox is a cloud storage and file synchronization platform that automatically syncs files across a user's devices and enables sharing and collaboration through a desktop app, mobile app, and web browser.$q$, $q$Beyond core file storage, Dropbox has expanded into an ecosystem of collaboration tools, including Dropbox Paper for documents, Dropbox Sign for e-signatures, and Dropbox Dash for AI-powered search across connected cloud apps.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('09bfad13-d346-4bb4-8adf-3ff6863d687e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Block-level sync technology only transfers the changed portions of a file, keeping synchronization fast even for large documents, while file version history lets users restore earlier versions or recover deleted files.$q$, $q$Shared team folders, granular link and folder permissions, offline file access, and integrations with tools like Slack, Zoom, and Microsoft Office support collaboration for both individuals and teams.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('09bfad13-d346-4bb4-8adf-3ff6863d687e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Dropbox's free Basic plan includes 2GB of storage. Personal paid plans include Plus (2TB, around $11.99/month) and Professional (3TB, around $19.99/month), both cheaper when billed annually.$q$, $q$Business plans include Standard (starts around $18-20/user/month, 3-user minimum, pooled team storage from 9TB), Advanced (larger storage and security controls), and a custom-priced Enterprise plan for large organizations with dedicated support and compliance features.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('09bfad13-d346-4bb4-8adf-3ff6863d687e', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('09bfad13-d346-4bb4-8adf-3ff6863d687e', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
