INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('09bfad13-d346-4bb4-8adf-3ff6863d687e', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d81fd94a-547f-4b52-8585-6375a6414c6d', $q$Legally binding e-signatures$q$, $q$Collect court-admissible electronic signatures with a full audit trail attached to every document.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d81fd94a-547f-4b52-8585-6375a6414c6d', $q$Reusable templates$q$, $q$Save frequently used documents as templates to speed up sending repeat contracts and forms.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d81fd94a-547f-4b52-8585-6375a6414c6d', $q$Multi-signer workflows$q$, $q$Route documents to multiple signers in a configurable signing order.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d81fd94a-547f-4b52-8585-6375a6414c6d', $q$In-person signing$q$, $q$Collect a signature on a single shared device for face-to-face signing situations.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d81fd94a-547f-4b52-8585-6375a6414c6d', $q$REST API for developers$q$, $q$Embed e-signature workflows directly into third-party applications and products.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d81fd94a-547f-4b52-8585-6375a6414c6d', $q$Audit trail and tracking$q$, $q$Every view, field entry, and signature event is logged to create a tamper-evident record.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d81fd94a-547f-4b52-8585-6375a6414c6d', $q$Third-party integrations$q$, $q$Connects natively with Dropbox, Google Drive, Slack, Salesforce, and HubSpot.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d81fd94a-547f-4b52-8585-6375a6414c6d', $q$Admin and security controls$q$, $q$Higher-tier plans add SSO, custom branding, and advanced reporting for larger organizations.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d81fd94a-547f-4b52-8585-6375a6414c6d', $q$Free plan and low-cost Essentials tier make it accessible for individuals and freelancers$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d81fd94a-547f-4b52-8585-6375a6414c6d', $q$Developer-friendly API makes it popular for embedding e-signature into other products$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d81fd94a-547f-4b52-8585-6375a6414c6d', $q$Simpler, more transparent pricing than several larger competitors$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d81fd94a-547f-4b52-8585-6375a6414c6d', $q$Deep integration with the broader Dropbox file-storage ecosystem$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d81fd94a-547f-4b52-8585-6375a6414c6d', $q$Standard plan requires a minimum of 2 paid users, adding cost for solo users needing team features$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d81fd94a-547f-4b52-8585-6375a6414c6d', $q$Fewer advanced document-workflow features than category leader DocuSign$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d81fd94a-547f-4b52-8585-6375a6414c6d', $q$Premium tier pricing is custom and not published, requiring a sales conversation$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d81fd94a-547f-4b52-8585-6375a6414c6d', $q$Free plan is limited to just 3 signature requests per month$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d81fd94a-547f-4b52-8585-6375a6414c6d', $q$Is Dropbox Sign the same as HelloSign?$q$, $q$Yes, Dropbox Sign was formerly known as HelloSign. Dropbox acquired HelloSign in 2019 and rebranded it as Dropbox Sign in October 2022.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d81fd94a-547f-4b52-8585-6375a6414c6d', $q$How much does Dropbox Sign cost?$q$, $q$Dropbox Sign offers a free plan with 3 signature requests per month, an Essentials plan starting at $15/month, a Standard plan starting at $25 per user per month, and custom-priced Premium plans.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d81fd94a-547f-4b52-8585-6375a6414c6d', $q$Does Dropbox Sign have an API?$q$, $q$Yes, Dropbox Sign offers a REST API that developers commonly use to embed e-signature workflows directly into their own applications.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d81fd94a-547f-4b52-8585-6375a6414c6d', $q$Are Dropbox Sign signatures legally binding?$q$, $q$Yes, Dropbox Sign collects legally binding electronic signatures with a full audit trail documenting every action taken on a signed document.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d81fd94a-547f-4b52-8585-6375a6414c6d', $q$What are the main alternatives to Dropbox Sign?$q$, $q$The most common alternatives are DocuSign, Adobe Acrobat Sign, PandaDoc, and SignWell.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d81fd94a-547f-4b52-8585-6375a6414c6d', $q$Do I need a Dropbox account to use Dropbox Sign?$q$, $q$No, Dropbox Sign can be used as a standalone product with its own account, separate from a general Dropbox storage account.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d81fd94a-547f-4b52-8585-6375a6414c6d', $q$Sales contract signing$q$, $q$Sales teams send proposals and contracts for signature and track completion status in real time.$q$, $q$Sales and business development teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d81fd94a-547f-4b52-8585-6375a6414c6d', $q$HR document workflows$q$, $q$HR teams use templates to send offer letters, NDAs, and onboarding paperwork for signature.$q$, $q$HR and people operations teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d81fd94a-547f-4b52-8585-6375a6414c6d', $q$Embedded e-signature in SaaS products$q$, $q$Software companies use the Dropbox Sign API to add native e-signature functionality inside their own applications.$q$, $q$Software developers and product teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d81fd94a-547f-4b52-8585-6375a6414c6d', $q$Free$q$, $q$Free$q$, $q$Free$q$, NULL, $q$["3 signature requests per month","Unlimited self-signing"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d81fd94a-547f-4b52-8585-6375a6414c6d', $q$Essentials$q$, $q$$15/month$q$, $q$Monthly, 1 user$q$, NULL, $q$["Unlimited signature requests","Reusable templates"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d81fd94a-547f-4b52-8585-6375a6414c6d', $q$Standard$q$, $q$$25/user/month$q$, $q$Monthly, 2-user minimum$q$, NULL, $q$["Unlimited signature requests per user","Team templates","Additional integrations"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d81fd94a-547f-4b52-8585-6375a6414c6d', $q$Premium$q$, $q$Custom pricing$q$, $q$Custom / annual contract$q$, NULL, $q$["Advanced admin and reporting","Custom branding","SSO and full API access"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d81fd94a-547f-4b52-8585-6375a6414c6d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Dropbox Sign, formerly known as HelloSign, is an electronic signature platform that lets businesses send documents for signature, collect legally binding e-signatures, and track the resulting audit trail entirely online.$q$, $q$Acquired by Dropbox in 2019 for approximately $230 million and rebranded from HelloSign in 2022, Dropbox Sign operates as part of Dropbox's broader document workflow and collaboration ecosystem while retaining its own pricing and product experience.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d81fd94a-547f-4b52-8585-6375a6414c6d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core capabilities include reusable signature templates, multi-signer workflows with configurable signing order, in-person signing on a single device, and a tamper-evident audit trail attached to every completed document.$q$, $q$A REST API lets developers embed e-signature workflows directly into their own products, and native integrations connect Dropbox Sign to Dropbox, Google Drive, Slack, Salesforce, and HubSpot.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d81fd94a-547f-4b52-8585-6375a6414c6d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Dropbox Sign offers a free plan with 3 signature requests per month and unlimited self-signing. The Essentials plan starts at $15/month for one user with unlimited signature requests, and the Standard plan starts at $25 per user per month with a 2-user minimum.$q$, $q$A Premium plan is available at custom pricing for larger organizations needing advanced admin controls, custom branding, SSO, and full API access.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d81fd94a-547f-4b52-8585-6375a6414c6d', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d81fd94a-547f-4b52-8585-6375a6414c6d', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d81fd94a-547f-4b52-8585-6375a6414c6d', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d81fd94a-547f-4b52-8585-6375a6414c6d', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d81fd94a-547f-4b52-8585-6375a6414c6d', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d81fd94a-547f-4b52-8585-6375a6414c6d', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d81fd94a-547f-4b52-8585-6375a6414c6d', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bb14a945-8442-4aa1-a8a7-f9b5b4d49f38', $q$Real-time email generation$q$, $q$Finds and verifies professional email addresses on the fly using proprietary algorithms rather than a stored database.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bb14a945-8442-4aa1-a8a7-f9b5b4d49f38', $q$GDPR-compliant by design$q$, $q$No standing database of personal data is retained, supporting structural GDPR compliance for EU-focused sales teams.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bb14a945-8442-4aa1-a8a7-f9b5b4d49f38', $q$Native CRM integrations$q$, $q$Automatically enriches and deduplicates contacts inside Salesforce, HubSpot, and Pipedrive.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bb14a945-8442-4aa1-a8a7-f9b5b4d49f38', $q$File and spreadsheet enrichment$q$, $q$Upload CSV, XLS, or TXT files, or enrich contacts directly inside Google Sheets via a native add-on.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bb14a945-8442-4aa1-a8a7-f9b5b4d49f38', $q$LinkedIn-based enrichment$q$, $q$Growth-tier plans enrich contacts from LinkedIn profile URLs without requiring a LinkedIn login.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bb14a945-8442-4aa1-a8a7-f9b5b4d49f38', $q$Company data enrichment$q$, $q$Matches company names to correct domains and detects when a contact changes companies.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bb14a945-8442-4aa1-a8a7-f9b5b4d49f38', $q$API and MCP access$q$, $q$Developers can integrate enrichment into custom tools via API, including MCP-compatible access for AI-agent workflows.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bb14a945-8442-4aa1-a8a7-f9b5b4d49f38', $q$Pay-on-success credit model$q$, $q$Credits are re-issued when an email address cannot be found, reducing wasted spend on failed lookups.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bb14a945-8442-4aa1-a8a7-f9b5b4d49f38', $q$Strong GDPR compliance positioning through a real-time, no-stored-database architecture$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bb14a945-8442-4aa1-a8a7-f9b5b4d49f38', $q$Native, automatic CRM integrations reduce manual data-cleaning work$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bb14a945-8442-4aa1-a8a7-f9b5b4d49f38', $q$Pay-on-success credit model limits cost from unsuccessful email searches$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bb14a945-8442-4aa1-a8a7-f9b5b4d49f38', $q$Growth plan credits roll over month to month instead of expiring$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bb14a945-8442-4aa1-a8a7-f9b5b4d49f38', $q$Entry-level Starter plan credits do not roll over between months$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bb14a945-8442-4aa1-a8a7-f9b5b4d49f38', $q$Pricing in euros may be less predictable for non-European customers due to currency fluctuation$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bb14a945-8442-4aa1-a8a7-f9b5b4d49f38', $q$Enterprise pricing is custom and not published, requiring a sales conversation for high-volume needs$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bb14a945-8442-4aa1-a8a7-f9b5b4d49f38', $q$Real-time verification approach can be slower for very large bulk enrichment jobs than pre-built database lookups$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bb14a945-8442-4aa1-a8a7-f9b5b4d49f38', $q$What does Dropcontact do?$q$, $q$Dropcontact finds and verifies B2B professional email addresses in real time and automatically cleans, deduplicates, and enriches contact and company records in a CRM.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bb14a945-8442-4aa1-a8a7-f9b5b4d49f38', $q$How much does Dropcontact cost?$q$, $q$Dropcontact's Starter plan costs €79/month for 500 credits, the Growth plan costs €120/month with rollover credits and LinkedIn enrichment, and Enterprise offers custom pricing for 200,000+ credits per month.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bb14a945-8442-4aa1-a8a7-f9b5b4d49f38', $q$Is Dropcontact GDPR compliant?$q$, $q$Yes, Dropcontact markets itself as structurally GDPR-compliant because it does not store a database of personal contact data, generating and verifying emails in real time instead.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bb14a945-8442-4aa1-a8a7-f9b5b4d49f38', $q$Which CRMs does Dropcontact integrate with?$q$, $q$Dropcontact integrates natively with Salesforce, HubSpot, and Pipedrive, and also offers a Google Sheets add-on and a general API.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bb14a945-8442-4aa1-a8a7-f9b5b4d49f38', $q$Where is Dropcontact based?$q$, $q$Dropcontact is a French startup founded in 2016 and based in Paris, France.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bb14a945-8442-4aa1-a8a7-f9b5b4d49f38', $q$What are the main alternatives to Dropcontact?$q$, $q$Common alternatives include Apollo.io, Hunter, ZoomInfo, Lusha, and the newer French competitor FullEnrich.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bb14a945-8442-4aa1-a8a7-f9b5b4d49f38', $q$Sales prospecting email finding$q$, $q$Sales development reps use Dropcontact to find verified professional email addresses for new prospects before outreach.$q$, $q$Sales development representatives$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bb14a945-8442-4aa1-a8a7-f9b5b4d49f38', $q$CRM data cleaning and deduplication$q$, $q$Revenue operations teams use Dropcontact to automatically deduplicate and enrich existing CRM contact and company records.$q$, $q$Revenue operations and sales operations teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bb14a945-8442-4aa1-a8a7-f9b5b4d49f38', $q$GDPR-compliant enrichment for EU companies$q$, $q$European B2B companies use Dropcontact specifically for its real-time, no-stored-database architecture to satisfy GDPR compliance requirements.$q$, $q$EU-based B2B sales and marketing teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bb14a945-8442-4aa1-a8a7-f9b5b4d49f38', $q$Starter$q$, $q$€79/month$q$, $q$Monthly$q$, NULL, $q$["500 monthly credits","Email finding and verification","GDPR-compliant processing","API and MCP access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bb14a945-8442-4aa1-a8a7-f9b5b4d49f38', $q$Growth$q$, $q$€120/month$q$, $q$Monthly$q$, NULL, $q$["500 monthly credits (rollover)","LinkedIn enrichment","Company-change detection","Company data enrichment"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bb14a945-8442-4aa1-a8a7-f9b5b4d49f38', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Custom / annual contract$q$, NULL, $q$["200,000+ credits per month","Priority enrichment","Dedicated support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bb14a945-8442-4aa1-a8a7-f9b5b4d49f38', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Dropcontact is a French, GDPR-compliant B2B data enrichment platform that finds and verifies professional email addresses in real time and automatically cleans and deduplicates CRM records.$q$, $q$Unlike many competitors, Dropcontact does not rely on a pre-built database of stored contact data; it generates and verifies emails on the fly using proprietary algorithms and live SMTP verification, a design central to its GDPR compliance positioning.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bb14a945-8442-4aa1-a8a7-f9b5b4d49f38', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Dropcontact integrates natively with Salesforce, HubSpot, and Pipedrive to enrich and deduplicate contacts automatically, and also supports CSV/XLS/TXT file uploads, a Google Sheets add-on, and an API with MCP-compatible access.$q$, $q$Beyond email finding, the platform performs job-title cleaning and AI classification, detects company changes, and matches company names to correct domains, keeping CRM data accurate over time rather than just adding new contacts.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bb14a945-8442-4aa1-a8a7-f9b5b4d49f38', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Dropcontact's Starter plan costs €79/month for 500 monthly credits with core email finding and CRM integration features. The Growth plan costs €120/month, also with 500 monthly credits, but adds credit rollover, LinkedIn enrichment, and company-change detection.$q$, $q$An Enterprise plan offers custom pricing for accounts needing 200,000 or more credits per month, with priority processing and dedicated support. Dropcontact uses a pay-on-success model, re-crediting accounts when an email cannot be found.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('bb14a945-8442-4aa1-a8a7-f9b5b4d49f38', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('bb14a945-8442-4aa1-a8a7-f9b5b4d49f38', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('bb14a945-8442-4aa1-a8a7-f9b5b4d49f38', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f8fefc7b-8f41-4745-a164-82c127ab7a0f', $q$Custom content modeling$q$, $q$Define fully custom content types, fields, and taxonomies rather than working within a fixed site structure.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f8fefc7b-8f41-4745-a164-82c127ab7a0f', $q$Headless/decoupled architecture$q$, $q$Built-in REST and JSON:API support lets Drupal serve content to React, Vue, mobile apps, or any front end.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f8fefc7b-8f41-4745-a164-82c127ab7a0f', $q$Large contributed module ecosystem$q$, $q$Thousands of community-built modules add e-commerce, SEO, workflow, and integration capabilities.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f8fefc7b-8f41-4745-a164-82c127ab7a0f', $q$Granular role-based permissions$q$, $q$Fine-grained access control supports complex editorial workflows across large organizations.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f8fefc7b-8f41-4745-a164-82c127ab7a0f', $q$Multilingual support$q$, $q$Core support for over 100 languages makes Drupal a common choice for global and government websites.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f8fefc7b-8f41-4745-a164-82c127ab7a0f', $q$Multi-site management$q$, $q$A single Drupal codebase can power multiple related websites from shared infrastructure.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f8fefc7b-8f41-4745-a164-82c127ab7a0f', $q$Enterprise-grade security$q$, $q$A dedicated security team and coordinated disclosure process make Drupal a common choice for security-conscious organizations.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f8fefc7b-8f41-4745-a164-82c127ab7a0f', $q$Drupal CMS starter experience$q$, $q$A curated bundle of modules and an improved editorial experience aimed at making Drupal more approachable for marketing teams.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f8fefc7b-8f41-4745-a164-82c127ab7a0f', $q$Completely free, open-source core with no licensing cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f8fefc7b-8f41-4745-a164-82c127ab7a0f', $q$Exceptional flexibility for complex, custom content structures and large multi-site deployments$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f8fefc7b-8f41-4745-a164-82c127ab7a0f', $q$Strong security track record and dedicated security governance process$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f8fefc7b-8f41-4745-a164-82c127ab7a0f', $q$Large, active global community with extensive contributed modules and themes$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f8fefc7b-8f41-4745-a164-82c127ab7a0f', $q$Steeper learning curve than page-builder-style CMS platforms like WordPress or Squarespace$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f8fefc7b-8f41-4745-a164-82c127ab7a0f', $q$Total cost of ownership can be high once development, hosting, and maintenance are factored in$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f8fefc7b-8f41-4745-a164-82c127ab7a0f', $q$Smaller market share and talent pool compared to WordPress, making developers harder to find$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f8fefc7b-8f41-4745-a164-82c127ab7a0f', $q$Contributed modules vary in quality and maintenance level, requiring careful vetting$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f8fefc7b-8f41-4745-a164-82c127ab7a0f', $q$Is Drupal free?$q$, $q$Yes, Drupal core is entirely free and open source under the GNU General Public License. Costs come from hosting, development, and optional commercial support.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f8fefc7b-8f41-4745-a164-82c127ab7a0f', $q$Who created Drupal?$q$, $q$Drupal was created by Dries Buytaert, who released the software publicly in January 2001 after building it as a student project at the University of Antwerp.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f8fefc7b-8f41-4745-a164-82c127ab7a0f', $q$What is Drupal used for?$q$, $q$Drupal is used to build websites and web applications ranging from simple sites to complex, highly customized platforms, and is especially popular with government agencies, universities, and large enterprises.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f8fefc7b-8f41-4745-a164-82c127ab7a0f', $q$How does Drupal compare to WordPress?$q$, $q$Drupal offers more flexibility for complex custom content structures and is favored by large, security-conscious organizations, while WordPress has a larger market share, a gentler learning curve, and is more common for smaller sites and blogs.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f8fefc7b-8f41-4745-a164-82c127ab7a0f', $q$Can Drupal be used headless?$q$, $q$Yes, Drupal supports a fully headless or decoupled architecture through built-in REST and JSON:API capabilities, letting it serve content to any front-end framework.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f8fefc7b-8f41-4745-a164-82c127ab7a0f', $q$Who hosts Drupal commercially?$q$, $q$Major commercial Drupal hosting and platform providers include Acquia (co-founded by Drupal's creator), Pantheon, and Platform.sh.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f8fefc7b-8f41-4745-a164-82c127ab7a0f', $q$Government and public-sector websites$q$, $q$Government agencies use Drupal for its security track record, accessibility support, and ability to manage large volumes of structured content.$q$, $q$Government agencies and public-sector organizations$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f8fefc7b-8f41-4745-a164-82c127ab7a0f', $q$Enterprise multi-site management$q$, $q$Large organizations run multiple related websites from a single shared Drupal codebase and infrastructure.$q$, $q$Enterprise IT and digital teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f8fefc7b-8f41-4745-a164-82c127ab7a0f', $q$Headless content platform for custom apps$q$, $q$Development teams use Drupal as a decoupled content backend serving custom React or mobile front ends.$q$, $q$Web developers and digital agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f8fefc7b-8f41-4745-a164-82c127ab7a0f', $q$Drupal Core & Community Modules$q$, $q$Free$q$, $q$Free (open source)$q$, NULL, $q$["Full CMS core functionality","Thousands of free contributed modules and themes","GPL open-source license","Community support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f8fefc7b-8f41-4745-a164-82c127ab7a0f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Drupal is a free, open-source content management system used to build everything from simple websites to complex, highly customized web applications, known for letting developers define fully custom content types and data structures rather than assuming a fixed site format.$q$, $q$Released under the GNU General Public License, Drupal core carries no licensing fee, and the platform is extended through thousands of community-built contributed modules and themes.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f8fefc7b-8f41-4745-a164-82c127ab7a0f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Drupal supports fully custom content types, fields, and taxonomies, along with a headless/decoupled architecture through built-in REST and JSON:API support for serving content to React, Vue, or mobile front ends.$q$, $q$A large contributed-module ecosystem adds capabilities like advanced SEO tools, e-commerce, workflow management, and multilingual support (Drupal ships with support for over 100 languages out of the box), while granular role-based permissions support complex editorial and governance workflows.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f8fefc7b-8f41-4745-a164-82c127ab7a0f', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Drupal core is entirely free and open source, with no licensing cost to download, install, or modify the software. Real-world costs come from hosting, development time, and optional commercial support.$q$, $q$Commercial Drupal hosting and platform providers such as Acquia, Pantheon, and Platform.sh offer tiered plans ranging from modest per-site hosting to enterprise managed contracts priced in the thousands of dollars per month, while self-hosting on general infrastructure is also common.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f8fefc7b-8f41-4745-a164-82c127ab7a0f', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
